205	// loadExecutionBundleDetail returns the same Execution but with prompt /
206	// manifest / result string bodies attached for execution(id:) lookups.
207	func loadExecutionBundleDetail(projectID, projectRoot, bundleDirAbs, bundleID string) *ddxgraphql.Execution {
208		exec := loadExecutionBundle(projectID, projectRoot, bundleDirAbs, bundleID)
209		if exec == nil {
210			return nil
211		}
212		if data, err := os.ReadFile(filepath.Join(bundleDirAbs, "prompt.md")); err == nil {
213			clamped, _, _ := evidence.ClampOutput(string(data), serverInlineCapBytes)
214			exec.Prompt = &clamped
215		}
216		if data, err := os.ReadFile(filepath.Join(bundleDirAbs, "manifest.json")); err == nil {
217			clamped, _, _ := evidence.ClampOutput(string(data), serverInlineCapBytes)
218			exec.Manifest = &clamped
219		}
220		if data, err := os.ReadFile(filepath.Join(bundleDirAbs, "result.json")); err == nil {
