227	// scanExecutionBundles enumerates `.ddx/executions/` for one project, returns
228	// merged Execution records sorted newest-first.
229	func scanExecutionBundles(projectID, projectRoot string) []*ddxgraphql.Execution {
230		dir := filepath.Join(projectRoot, agent.ExecuteBeadArtifactDir)
231		entries, err := os.ReadDir(dir)
232		if err != nil {
233			return nil
234		}
235		out := make([]*ddxgraphql.Execution, 0, len(entries))
236		for _, entry := range entries {
237			if !entry.IsDir() {
238				continue
239			}
240			name := entry.Name()
241			if !looksLikeBundleID(name) {
242				continue
243			}
244			bundleDirAbs := filepath.Join(dir, name)
245			if exec := loadExecutionBundle(projectID, projectRoot, bundleDirAbs, name); exec != nil {
246				out = append(out, exec)
247			}
248		}
249		sort.Slice(out, func(i, j int) bool {
250			return out[i].CreatedAt > out[j].CreatedAt
251		})
252		return out
253	}
