255	// looksLikeBundleID checks for the YYYYMMDDTHHMMSS-<hex> shape used by
256	// execute-bead, plus a permissive fallback that accepts any non-special name.
257	// It rejects the special "mirror-index.jsonl" file and other reserved names.
258	func looksLikeBundleID(name string) bool {
259		if name == "" || strings.HasPrefix(name, ".") {
260			return false
261		}
262		if strings.Contains(name, ".jsonl") || strings.Contains(name, ".json") {
263			return false
264		}
265		return true
266	}
