302	// GetExecutionsGraphQL implements the optional ExecutionsStateProvider.
303	func (s *ServerState) GetExecutionsGraphQL(projectID string, filter ddxgraphql.ExecutionFilter) []*ddxgraphql.Execution {
304		if projectID == "" {
305			return nil
306		}
307		proj, ok := s.GetProjectByID(projectID)
308		if !ok {
309			return nil
310		}
311		all := scanExecutionBundles(projectID, proj.Path)
312		return applyExecutionFilter(all, filter)
313	}
