1546	// ApplyLandResultToExecuteBeadResult maps a LandResult onto an
1547	// ExecuteBeadResult so the execute-bead loop sees the correct final status.
1548	// It is the coordinator-pattern replacement for ApplyLandingToResult.
1549	func ApplyLandResultToExecuteBeadResult(res *ExecuteBeadResult, land *LandResult) {
1550		if land == nil || res == nil {
1551			return
1552		}
1553		switch land.Status {
1554		case "landed":
1555			// Fast-forward or merge commit — either way the target branch now
1556			// contains the worker's result. ResultRev's own parent is still
1557			// BaseRev so replay fidelity is preserved.
1558			res.Outcome = "merged"
1559			res.Reason = ""
1560			res.PreserveRef = ""
1561			if land.Merged {
1562				res.Reason = "merged onto current tip"
1563			}
1564			if land.PushConflict {
1565				res.Reason = PushConflictReasonPrefix + " " + land.PushError
1566			} else if land.PushFailed {
1567				res.Reason = PushFailedReasonPrefix + " " + land.PushError
1568			}
1569			if land.CheckoutSyncDeferred {
1570				detail := "checkout_sync_deferred"
1571				if len(land.CheckoutSyncDeferredPaths) > 0 {
1572					detail += ": " + strings.Join(land.CheckoutSyncDeferredPaths, ", ")
1573				}
1574				if res.Reason == "" {
1575					res.Reason = detail
1576				} else {
1577					res.Reason += "; " + detail
1578				}
1579			}
1580			// NewTip reflects the ref actually on the target branch (either
1581			// ResultRev on the ff path or the merge commit SHA on the merge path).
1582			if land.NewTip != "" {
1583				res.ResultRev = land.NewTip
1584			}
1585		case "preserved":
1586			res.Outcome = "preserved"
1587			res.Reason = land.Reason
1588			res.PreserveRef = land.PreserveRef
1589		case "no-changes":
1590			// Only overwrite when the worker itself did not already report
1591			// a richer no-changes rationale.
1592			if res.Outcome == "" || res.Outcome == ExecuteBeadOutcomeTaskSucceeded {
1593				res.Outcome = "no-changes"
1594			}
1595			if res.Reason == "" {
1596				res.Reason = land.Reason
1597			}
1598		}
1599		// Re-classify loop-visible status from the landing outcome.
1600		reasonForStatus := res.Reason
1601		if land.Status == "preserved" {
1602			// Route preserve reasons through the land-conflict classifier so the
1603			// loop sees land_conflict (not generic success).
1604			reasonForStatus = "merge conflict"
1605		}
1606		res.Status = ClassifyExecuteBeadStatus(res.Outcome, res.ExitCode, reasonForStatus)
1607		res.Detail = ExecuteBeadStatusDetail(res.Status, res.Reason, res.Error)
1608	}
