	if err := os.WriteFile(filepath.Join(bundleDir, "result.json"), rb, 0o644); err != nil {
		t.Fatal(err)
	}

	s := newServerStateForTest(t, root)
	all := s.GetExecutionsGraphQL("proj-test", ddxgraphql.ExecutionFilter{})
	if len(all) != 1 {
		t.Fatalf("expected 1 execution, got %d", len(all))
	}
	exec := all[0]

	// result_rev backwards-compat field.
	if exec.ResultRev == nil || *exec.ResultRev != resultSHA {
		t.Errorf("ResultRev: want %q, got %v", resultSHA, exec.ResultRev)
	}
	// New explicit fields.
	if exec.ImplementationRev == nil || *exec.ImplementationRev != implSHA {
		t.Errorf("ImplementationRev: want %q, got %v", implSHA, exec.ImplementationRev)
	}
	if exec.LandedRev == nil || *exec.LandedRev != landedSHA {
		t.Errorf("LandedRev: want %q, got %v", landedSHA, exec.LandedRev)
	}
	if exec.EvidenceRev == nil || *exec.EvidenceRev != evidenceSHA {
		t.Errorf("EvidenceRev: want %q, got %v", evidenceSHA, exec.EvidenceRev)
	}
}

// TestExecutionBundle_RevisionTriplet_ResultFallback confirms that when the
// triplet fields are present in result.json (not manifest.json) they are still
// surfaced — manifest takes priority when both are present.
func TestExecutionBundle_RevisionTriplet_ResultFallback(t *testing.T) {
	const (
		implSHA   = "rimpl111rimpl222rimpl333rimpl444rimpl555"
		landedSHA = "rland111rland222rland333rland444rland555"
	)

	root := t.TempDir()
	bundleID := "20260508T020000-revfallback"
	bundleDir := filepath.Join(root, agent.ExecuteBeadArtifactDir, bundleID)
	if err := os.MkdirAll(bundleDir, 0o755); err != nil {
		t.Fatal(err)
	}

	// Manifest has no rev triplet fields.
	manifest := map[string]any{
		"attempt_id": bundleID,
		"bead_id":    "ddx-fallback",
		"base_rev":   "base0000",
		"result_rev": landedSHA,
		"created_at": "2026-05-08T02:00:00Z",
	}
	mb, _ := json.Marshal(manifest)
	if err := os.WriteFile(filepath.Join(bundleDir, "manifest.json"), mb, 0o644); err != nil {
		t.Fatal(err)
	}
	// result.json carries the triplet.
	result := map[string]any{
		"bead_id":            "ddx-fallback",
		"attempt_id":         bundleID,
		"outcome":            "merged",
		"exit_code":          0,
		"implementation_rev": implSHA,
		"landed_rev":         landedSHA,
	}
	rb, _ := json.Marshal(result)
	if err := os.WriteFile(filepath.Join(bundleDir, "result.json"), rb, 0o644); err != nil {
		t.Fatal(err)
	}

	s := newServerStateForTest(t, root)
	all := s.GetExecutionsGraphQL("proj-test", ddxgraphql.ExecutionFilter{})
	if len(all) != 1 {
		t.Fatalf("expected 1 execution, got %d", len(all))
	}
	exec := all[0]

	if exec.ImplementationRev == nil || *exec.ImplementationRev != implSHA {
		t.Errorf("ImplementationRev from result.json: want %q, got %v", implSHA, exec.ImplementationRev)
	}
	if exec.LandedRev == nil || *exec.LandedRev != landedSHA {
		t.Errorf("LandedRev from result.json: want %q, got %v", landedSHA, exec.LandedRev)
	}
}

// Perf-shaped sanity check: scanning 1k bundles should complete promptly so
// the list-view p95 budget (200ms HTTP) is realistic on a dev laptop.
func TestExecutions_ListPerf_1000(t *testing.T) {

data.output:
	resultRev := commitWorkerChange(t, root, "worker-out.txt", "worker out\n")

	res := &agent.ExecuteBeadResult{
		BeadID:       beadID,
		AttemptID:    attemptID,
		BaseRev:      initialTip,
		ResultRev:    resultRev,
		ExitCode:     0,
		Outcome:      agent.ExecuteBeadOutcomeTaskSucceeded,
		ExecutionDir: filepath.Join(".ddx", "executions", attemptID),
		ManifestFile: manifestRel,
	}

	m := NewWorkerManager(root)
	t.Cleanup(func() { m.LandCoordinators.StopAll() })
	rec := &recordingSubmitter{inner: m.LandCoordinators.Get(root)}

	var logBuf bytes.Buffer
	require.NoError(t, evaluateGatesAndSubmit(root, res, &agent.RealGitOps{}, rec, landSafetyConfig{}, &logBuf))

	// Coordinator MUST have been called (no gates → submit path).
	assert.Len(t, rec.calls, 1, "coordinator must be called when no governing IDs")

	// Target ref MUST have advanced.
	tipAfter := mustResolveRef(t, root, "refs/heads/main")
	assert.NotEqual(t, initialTip, tipAfter, "main must advance when no governing IDs")

	// NO checks.json should exist (gate eval did not run).
	checksAbs := filepath.Join(root, ".ddx", "executions", attemptID, "checks.json")
	_, statErr := os.Stat(checksAbs)
	assert.True(t, os.IsNotExist(statErr), "checks.json must not exist when no governing IDs")

	// NO gate-pin ref should remain. BuildLandingGateContext returns
	// ("", nil, noop, nil) when governing IDs are empty, so no pin is ever
	// created — the cleanup is the noop.
	pinRef := "refs/ddx/gate-pins/" + beadID + "/" + attemptID
	out, pinErr := exec.Command("git", "-C", root, "rev-parse", "--verify", pinRef).Output()
	assert.Error(t, pinErr, "gate-pin ref must not exist (output=%q)", string(out))

	// res state: outcome=merged.
	assert.Equal(t, "merged", res.Outcome)
}

// mustResolveRef returns the SHA the ref points at, failing the test on error.
func mustResolveRef(t *testing.T, root, ref string) string {
	t.Helper()
	out, err := exec.Command("git", "-C", root, "rev-parse", "--verify", ref).Output()
	require.NoError(t, err, "rev-parse %s", ref)
	return strings.TrimSpace(string(out))
}

